31	type AuthoringDraftProps = {
32	  schemeRowsFromDoc: RoomColorSchemeRow[];
33	  onUpsertSemantic: (cmd: Record<string, unknown>) => void;
34	};
35	
36	function RoomColourSchemeAuthoringDraft({
37	  schemeRowsFromDoc,
38	  onUpsertSemantic,
39	}: AuthoringDraftProps) {
40	  const [draftRows, setDraftRows] = useState<RoomColorSchemeRow[]>(() =>
41	    initialDraftRows(schemeRowsFromDoc),
42	  );
43	  const [applyError, setApplyError] = useState<string | null>(null);
44	
45	  const onApply = () => {
46	    setApplyError(null);
47	    const sanitized: RoomColorSchemeRow[] = [];
48	
49	    for (const r of draftRows) {
50	      if (!rowHasProgrammeOrDepartment(r)) continue;
51	      const hex = normalizeSchemeColorHex(r.schemeColorHex ?? '');
52	      if (!hex) {
53	        setApplyError('Each filled row needs a valid #RRGGBB hex colour.');
54	        return;
55	      }
56	      const prog = typeof r.programmeCode === 'string' ? r.programmeCode.trim() : '';
57	      const dept = typeof r.department === 'string' ? r.department.trim() : '';
58	
59	      sanitized.push({
60	        schemeColorHex: hex,
61	        ...(prog ? { programmeCode: prog } : {}),
62	
63	        ...(dept ? { department: dept } : {}),
64	      });
65	    }
66	
67	    if (!sanitized.length) {
68	      setApplyError('Add at least one row with programme and/or department before applying.');
69	      return;
70	    }
71	
72	    const canon = canonicalRoomSchemeRows(sanitized);
73	
74	    onUpsertSemantic(buildUpsertRoomColorSchemeCmdPayload(canon));
75	  };
