                <label className="flex min-w-0 flex-col text-[9px] text-muted">
                  scale
                  <input
                    className="mt-0.5 rounded border border-border bg-background px-0.5 py-0.5 font-mono text-[9px]"
                    type="number"
                    min={0.01}
                    step={0.1}
                    value={row.scale ?? 1}
                    onChange={(e) => {
                      const v = Number(e.target.value);
                      setCtxRows((rows) =>
