666	  /* ── Global hotkeys: 1–7 modes, ?, V/W/D/M/S/etc tools ─────────────── */
667	  useEffect(() => {
668	    const onKey = (event: globalThis.KeyboardEvent): void => {
669	      const target = event.target as HTMLElement | null;
670	      if (target) {
671	        const tag = target.tagName;
672	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
673	        if (target.isContentEditable) return;
674	      }
675	      const fromMode = modeForHotkey(event.key);
676	      if (fromMode) {
677	        event.preventDefault();
678	        handleModeChange(fromMode);
679	        return;
680	      }
681	      if (event.key === '?') {
682	        event.preventDefault();
683	        setCheatsheetOpen((v) => !v);
684	        return;
685	      }
686	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
687	        event.preventDefault();
688	        setPaletteOpen((v) => !v);
689	        return;
690	      }
691	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
692	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
693	        event.preventDefault();
694	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
695	        return;
696	      }
697	      // Close active tab — Ctrl/⌘+W.
698	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
699	        event.preventDefault();
700	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
701	        return;
702	      }
703	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
704	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
705	        event.preventDefault();
706	        void handleUndoRedo(event.shiftKey ? false : true);
707	        return;
708	      }
709	      // Ortho snap hold on Shift
710	      if (event.shiftKey) setOrthoSnapHold(true);
711	      // Tool hotkeys — match the spec'd letters from TOOL_REGISTRY.
712	      const upper = event.key.length === 1 ? event.key.toUpperCase() : event.key;
713	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
714	      const tool = (Object.values(toolRegistry) as { id: ToolId; hotkey: string }[]).find(
715	        (tool) => tool.hotkey === hotkeyLabel,
716	      );
717	      if (tool) {
718	        const legacy = toolIdToLegacy(tool.id);
719	        if (legacy) {
720	          event.preventDefault();
721	          setPlanTool(legacy);
722	        }
723	      }
724	    };
725	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
726	      if (!event.shiftKey) setOrthoSnapHold(false);
727	    };
728	    document.addEventListener('keydown', onKey);
729	    document.addEventListener('keyup', onKeyUp);
730	    return () => {
731	      document.removeEventListener('keydown', onKey);
732	      document.removeEventListener('keyup', onKeyUp);
733	    };
734	  }, [handleModeChange, handleUndoRedo, setPlanTool, setOrthoSnapHold]);
