const canvasContainerStyle: CSSProperties = {
  position: 'relative',
  width: '100%',
  height: '100%',
};

function FloatingPalette({
  mode,
  activeTool,
  onToolSelect,
  disabledContext,
}: {
  mode: WorkspaceMode;
  activeTool: ToolId;
  onToolSelect: (id: ToolId) => void;
  disabledContext: ToolDisabledContext;
}): JSX.Element | null {
  if (mode === 'sheet' || mode === 'schedule' || mode === 'agent') return null;
  return (
    <div
      style={{
        position: 'absolute',
        top: 12,
        left: '50%',
        transform: 'translateX(-50%)',
        zIndex: 10,
      }}
    >
      <ToolPalette
        mode={mode}
        activeTool={activeTool}
        onToolSelect={onToolSelect}
        disabledContext={disabledContext}
      />
    </div>
  );
}

function CanvasMount({
  mode,
  viewerMode,
  activeLevelId,
  elementsById,
  onSemanticCommand,
  cameraHandleRef,
  initialCamera,
  preferredSheetId,
  modelId,
  wsOn,
  onPersistViewpointField,
}: {
  mode: WorkspaceMode;
  viewerMode: 'plan_canvas' | 'orbit_3d';
  activeLevelId: string;
  elementsById: Record<string, Element>;
  onSemanticCommand: (cmd: Record<string, unknown>) => void;
  cameraHandleRef?: RefObject<PlanCameraHandle | null>;
  initialCamera?: { centerMm?: { xMm: number; yMm: number }; halfMm?: number };
  preferredSheetId?: string;
  modelId?: string;
  wsOn?: boolean;
  onPersistViewpointField?: (p: { elementId: string; key: string; value: string }) => void | Promise<void>;
}): JSX.Element {
  if (mode === 'plan-3d') {
    return (
      <div
        style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', height: '100%', width: '100%' }}
      >
        <div style={{ position: 'relative', borderRight: '1px solid var(--color-border)' }}>
          <PlanCanvas
            wsConnected={wsOn ?? false}
            activeLevelResolvedId={activeLevelId ?? ''}
            onSemanticCommand={onSemanticCommand}
            cameraHandleRef={cameraHandleRef}
            initialCamera={initialCamera}
          />
        </div>
        <div style={{ position: 'relative' }}>
          <Viewport wsConnected={wsOn ?? false} onPersistViewpointField={onPersistViewpointField} />
        </div>
      </div>
    );
  }
  if (mode === '3d') return <Viewport wsConnected={wsOn ?? false} onPersistViewpointField={onPersistViewpointField} />;
  if (mode === 'plan')
    return (
      <PlanCanvas
        wsConnected={wsOn ?? false}
        activeLevelResolvedId={activeLevelId}
        onSemanticCommand={onSemanticCommand}
        cameraHandleRef={cameraHandleRef}
        initialCamera={initialCamera}
      />
    );
  if (mode === 'section') return <SectionModeShell activeLevelLabel={activeLevelId} modelId={modelId} />;
  if (mode === 'sheet') return <SheetModeShell elementsById={elementsById} preferredSheetId={preferredSheetId} />;
  if (mode === 'schedule') return <ScheduleModeShell elementsById={elementsById} />;
  if (mode === 'agent')
    return <AgentReviewModeShell onApplyQuickFix={onSemanticCommand} />;
  return viewerMode === 'orbit_3d' ? (
    <Viewport wsConnected={wsOn ?? false} onPersistViewpointField={onPersistViewpointField} />
  ) : (
    <PlanCanvas
      wsConnected={wsOn ?? false}
      activeLevelResolvedId={activeLevelId}
      onSemanticCommand={onSemanticCommand}
    />
  );
}

function EmptyStateOverlay({
  headline,
  hint,
  ctaLabel,
  ctaPending,
  ctaError,
  onCta,
}: {
  headline: string;
  hint: string;
  ctaLabel: string | null;
  ctaPending: boolean;
  ctaError: string | null;
  onCta: () => void;
}): JSX.Element {
  return (
    <div
      role="status"
      aria-live="polite"
      style={{
        position: 'absolute',
        inset: 0,
        zIndex: 5,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        pointerEvents: 'none',
      }}
    >
      <div className="pointer-events-auto flex flex-col items-center gap-3 rounded-lg bg-surface/95 px-6 py-5 text-center shadow-elev-2 backdrop-blur">
        <div className="text-md font-medium text-foreground">{headline}</div>
        <div className="text-sm text-muted">{hint}</div>
        {ctaLabel ? (
          <button
            type="button"
            onClick={onCta}
            disabled={ctaPending}
            data-testid="canvas-empty-cta"
            className="rounded-md bg-accent px-4 py-1.5 text-sm font-medium text-accent-foreground shadow-elev-1 hover:bg-accent/90 disabled:cursor-not-allowed disabled:opacity-60"
          >
            {ctaPending ? 'Loading…' : ctaLabel}
