1	import { useCallback, useEffect, useRef, useState } from 'react';
2	
3	import type { Element, SiteContextObjectRow, SiteContextType } from '@bim-ai/core';
4	
5	import { Btn, Panel } from '@bim-ai/ui';
6	
7	import {
8	  boundaryAxisAlignedBoxMm,
9	  boundaryMmFromAnchorSize,
10	  buildUpsertSiteCmdPayload,
11	  type XY,
12	} from './siteAuthoringPayload';
13	
14	type LevelRow = Extract<Element, { kind: 'level' }>;
15	type SiteRow = Extract<Element, { kind: 'site' }>;
16	
17	const DEFAULT_SITE_ID = 'site-v0';
18	const DEFAULT_WIDTH_MM = 20_000;
19	const DEFAULT_DEPTH_MM = 15_000;
20	const DEFAULT_PAD_MM = 80;
21	const CONTEXT_TYPES: SiteContextType[] = [
22	  'tree',
23	  'shrub',
24	  'neighbor_proxy',
25	  'entourage',
26	];
27	
28	function sortedSites(elementsById: Record<string, Element>): SiteRow[] {
29	  return Object.values(elementsById)
30	    .filter((e): e is SiteRow => e.kind === 'site')
31	    .sort((a, b) => a.id.localeCompare(b.id));
32	}
33	
34	let nextContextDraftKey = 1;
35	
36	function emptyContextDraft(): SiteContextObjectRow & { _key: number } {
37	  nextContextDraftKey += 1;
38	  return {
39	    _key: nextContextDraftKey,
40	    id: '',
41	    contextType: 'tree',
42	    label: '',
43	    positionMm: { xMm: 0, yMm: 0 },
44	    scale: 1,
45	    category: 'site_entourage',
46	  };
47	}
48	
49	type Props = {
50	  revision: number;
51	  elementsById: Record<string, Element>;
52	  levels: LevelRow[];
53	  onUpsertSemantic: (cmd: Record<string, unknown>) => void;
54	};
55	
56	export function SiteAuthoringPanel({
57	  revision,
58	  elementsById,
59	  levels,
60	  onUpsertSemantic,
61	}: Props) {
62	  const elementsRef = useRef(elementsById);
63	  const levelsRef = useRef(levels);
64	  elementsRef.current = elementsById;
65	  levelsRef.current = levels;
66	
67	  const [siteId, setSiteId] = useState(DEFAULT_SITE_ID);
68	  const [name, setName] = useState('Site');
69	  const [referenceLevelId, setReferenceLevelId] = useState('');
70	  const [anchor, setAnchor] = useState<XY>({ xMm: 0, yMm: 0 });
71	  const [widthMm, setWidthMm] = useState(DEFAULT_WIDTH_MM);
72	  const [depthMm, setDepthMm] = useState(DEFAULT_DEPTH_MM);
73	  const [padMm, setPadMm] = useState(DEFAULT_PAD_MM);
74	  const [baseOffsetMm, setBaseOffsetMm] = useState(0);
75	  const [northDegText, setNorthDegText] = useState('');
76	  const [setbackText, setSetbackText] = useState('');
77	  const [ctxRows, setCtxRows] = useState<(SiteContextObjectRow & { _key: number })[]>([
78	    emptyContextDraft(),
79	  ]);
80	  const [applyError, setApplyError] = useState<string | null>(null);
81	
82	  const hydrateFromDoc = useCallback(() => {
83	    const els = elementsRef.current;
84	    const lvls = levelsRef.current;
85	    const sites = sortedSites(els);
86	    const primary = sites[0];
87	    const lv0 = lvls[0]?.id ?? '';
88	
89	    if (!primary) {
90	      setSiteId(DEFAULT_SITE_ID);
91	      setName('Site');
92	      setReferenceLevelId(lv0);
93	      setAnchor({ xMm: 0, yMm: 0 });
94	      setWidthMm(DEFAULT_WIDTH_MM);
95	      setDepthMm(DEFAULT_DEPTH_MM);
96	      setPadMm(DEFAULT_PAD_MM);
97	      setBaseOffsetMm(0);
98	      setNorthDegText('');
99	      setSetbackText('');
100	      setCtxRows([emptyContextDraft()]);
101	      return;
102	    }
103	
104	    const box = boundaryAxisAlignedBoxMm(primary.boundaryMm ?? []);
105	    const nextAnchor = box?.anchor ?? { xMm: 0, yMm: 0 };
106	    const w = box?.widthMm ?? DEFAULT_WIDTH_MM;
107	    const d = box?.depthMm ?? DEFAULT_DEPTH_MM;
108	
109	    setSiteId(primary.id);
110	    setName(primary.name ?? 'Site');
111	    setReferenceLevelId(primary.referenceLevelId ?? lv0);
112	    setAnchor(nextAnchor);
113	    setWidthMm(w);
