221	        return;
222	      }
223	      const sx = typeof r.scale === 'number' ? r.scale : 1;
224	      if (!Number.isFinite(sx) || sx <= 0) {
225	        setApplyError(`Context '${k}' scale must be > 0 when set (default 1).`);
226	        return;
227	      }
228	      if (!r.positionMm || typeof r.positionMm.xMm !== 'number' || typeof r.positionMm.yMm !== 'number') {
229	        setApplyError(`Context '${k}' positionMm requires numeric xMm and yMm.`);
230	        return;
231	      }
232	    }
233	
234	    const cmd = buildUpsertSiteCmdPayload({
235	      id: idTrim,
236	      name: name.trim() || 'Site',
237	      referenceLevelId: rid,
238	      boundaryMm: boundaryMmFromAnchorSize(
239	        anchor,
240	        Number(widthMm),
241	        Number(depthMm),
242	      ),
243	      padThicknessMm: pad,
244	      baseOffsetMm: bo,
245	      northDegCwFromPlanX: north,
246	      uniformSetbackMm: setback,
247	      contextObjects: payloads,
248	    });
249	    onUpsertSemantic(cmd);
250	  };
251	
252	  return (
253	    <Panel title="Site (pad boundary)">
254	      <div className="space-y-3 text-[11px]">
255	        <div className="rounded border border-border bg-muted/20 p-2 text-[10px] text-muted">
256	          <strong className="text-foreground">Evidence</strong> — boundary vertices{' '}
257	          <span className="font-mono">{boundaryMmResolved.length}</span>, context markers{' '}
258	          <span className="font-mono">{evidenceContextCount}</span>, ref level{' '}
259	          <span className="font-mono">{refLevelName}</span>. Bounded to{' '}
260	          <span className="font-mono">upsertSite</span>; no grading, contours, or survey import — pad
261	          is a simple prism.
262	        </div>
263	
