1	import type { Violation } from '@bim-ai/core';
2	
3	/** Human-oriented hint for where to look in the authoring UI (no new server fields). */
4	export function recommendedContextForRuleId(ruleId: string): string {
5	  switch (ruleId) {
6	    case 'schedule_sheet_viewport_missing':
7	      return 'Recommended: open the linked sheet, add or fix a schedule viewport (viewRef schedule:…).';
8	    case 'schedule_orphan_sheet_ref':
9	      return 'Recommended: Schedules — set or clear sheetId so the schedule references a real sheet.';
10	    case 'schedule_opening_identifier_missing':
11	      return 'Recommended: Schedules / properties — set door or window mark/name used on opening schedules.';
12	    case 'schedule_opening_orphan_host':
13	      return 'Recommended: Restore or re-host the opening onto a valid wall (wallId) so schedule rows resolve.';
14	    case 'schedule_opening_family_type_incomplete':
15	      return 'Recommended: Assign familyTypeId on the opening (type columns and type-driven schedules).';
16	    case 'schedule_opening_host_wall_type_incomplete':
17	      return 'Recommended: Assign wallTypeId on the host wall (hostWallTypeId / hostWallTypeDisplay columns).';
18	    case 'schedule_sheet_export_parity_csv_diverges':
19	    case 'schedule_sheet_export_parity_json_diverges':
20	    case 'schedule_sheet_export_parity_listing_diverges':
21	      return 'Recommended: Schedules — re-derive the schedule table; CSV / JSON / sheet listing row counts disagree.';
22	    case 'sheet_missing_titleblock':
23	      return 'Recommended: Sheet authoring — set title block symbol on this sheet.';
24	    case 'sheet_viewport_zero_extent':
25	      return 'Recommended: Sheet viewports — restore positive widthMm/heightMm for the listed viewport(s).';
26	    case 'sheet_viewport_unknown_ref':
27	      return 'Recommended: Sheet viewports — fix or remove the unresolved viewRef.';
